package com.evolua.subscription.interfaces.rest; import com.evolua.subscription.application.SubscriptionService; import com.evolua.subscription.infrastructure.security.CurrentUserProvider; import io.swagger.v3.oas.annotations.Operation; import jakarta.validation.Valid; import java.util.List; import org.springframework.http.HttpStatus; import org.springframework.http.ResponseEntity; import org.springframework.web.bind.annotation.*; @RestController @RequestMapping("/v1/subscriptions") public class SubscriptionController { private final SubscriptionService service; private final SubscriptionMapper mapper; private final CurrentUserProvider currentUserProvider; public SubscriptionController(SubscriptionService service, SubscriptionMapper mapper, CurrentUserProvider currentUserProvider) { this.service = service; this.mapper = mapper; this.currentUserProvider = currentUserProvider; } @PostMapping @Operation(summary = "Create Subscription") public ResponseEntity<ApiResponse<SubscriptionResponse>> create(@Valid @RequestBody SubscriptionRequest request) { var created = service.create(currentUserProvider.getCurrentUser().userId(), request.planCode(), request.status(), request.billingCycle(), request.premium()); return ResponseEntity.status(HttpStatus.CREATED).body(ApiResponse.success(201, "Created", mapper.toResponse(created))); } @GetMapping @Operation(summary = "List subscriptions") public ResponseEntity<ApiResponse<List<SubscriptionResponse>>> list() { return ResponseEntity.ok(ApiResponse.success(200, "Listed", service.list(currentUserProvider.getCurrentUser().userId()).stream().map(mapper::toResponse).toList())); } }
